import{_ as t,o as i,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F06_存貨與債務穩定度審計_財務分析專家.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F06_存貨與債務穩定度審計_財務分析專家.md"}'),e={name:"審計報告庫/財務審計/6257_矽格/20260430/F06_存貨與債務穩定度審計_財務分析專家.md"};function o(n,a,s,h,_,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="f06-存貨與債務穩定度審計-財務分析專家-審計報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務分析專家-審計報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：矽格存貨自2024Q4谷底4.15億攀升至2025Q4的5.88億（+41.7%），但原料佔比72.4%、製成品僅2.2%，屬封測代工正常備料結構，非滯銷囤貨；流動比2.13、速動比2.42，現金127億完全覆蓋全部短債4.19億逾30倍，流動性結構極為健全。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年12月最新公開財報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>存貨淨額：5.88億（2025Q4），YoY +41.7%（vs. 2024Q4之4.15億）</li><li>存貨週轉天數：13.2天（2025全年），符合封測代工高速周轉特性</li><li>流動比：2.13（2025Q4），速動比：2.42</li><li>短期借款：4.19億；長期借款：74.1億；應付公司債：29.8億；總負債：165.9億</li><li>權益總額：243.9億，負債比率：40.5%</li></ul></li><li><strong>診斷見解</strong>：存貨絕對金額雖創新高，但相對營收佔比僅3.9%（存貨5.88億 / 全年營收~151億），且組成結構健康——原料佔72%符合封測業大量採購晶粒封裝材料之營運模式，製成品僅2.2%排除滯銷風險。債務端雖總借款逾78億，但現金部位127億遠超全部有息負債，公司實質為「淨現金」狀態，流動性壓力為零。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、存貨金額變動趨勢與組成分析" tabindex="-1">一、存貨金額變動趨勢與組成分析 <a class="header-anchor" href="#一、存貨金額變動趨勢與組成分析" aria-label="Permalink to &quot;一、存貨金額變動趨勢與組成分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：存貨從2024Q1的4.50億逐季降至2024Q4的4.15億後，2025年出現明顯反轉，Q2達5.80億、Q4達5.88億，較2024谷底增長41.7%。</li><li><strong>深度見解</strong>：從年報存貨附註（第35頁）解構，原料佔72.4%（4.52億）、物料16.2%（1.01億）、在製品9.2%（0.57億）、製成品僅2.2%（0.14億）。製成品佔比極低，說明公司採「接單備料」模式，存貨增加主因是2025年營收成長11.4%帶動的採購量擴大，非去化困難。備抵跌價損失僅3,647萬（佔存貨成本5.8%），且2025年反而迴轉3,391萬利益，反映存貨品質良好、無減值壓力。</li></ul><h3 id="二、流動性資產覆蓋短期與長期債務能力" tabindex="-1">二、流動性資產覆蓋短期與長期債務能力 <a class="header-anchor" href="#二、流動性資產覆蓋短期與長期債務能力" aria-label="Permalink to &quot;二、流動性資產覆蓋短期與長期債務能力&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025Q4流動資產186.5億 vs. 流動負債87.6億，流動比2.13；扣除存貨後之速動資產為177.7億，速動比2.42。短期借款僅4.19億，現金127億對短債覆蓋倍數達30.4倍。</li><li><strong>深度見解</strong>：公司債務結構偏長期——長期借款74.1億 + 應付公司債29.8億 = 103.9億為長期資金，佔總有息負債（108.1億）的96.1%。此結構大幅降低再融資風險。利息保障倍數17.8倍（稅前利益38.9億 / 利息費用2.19億），遠高於安全水位3倍。實質計算：（現金127億 + 按攤銷後成本金融資產39.5億）/ 有息負債108.1億 = 1.91倍，即便在極端情境下以全部流動資產覆蓋全部負債（含非流動），仍無違約壓力。</li></ul><h3 id="三、跌價損失風險與產業去庫存壓力" tabindex="-1">三、跌價損失風險與產業去庫存壓力 <a class="header-anchor" href="#三、跌價損失風險與產業去庫存壓力" aria-label="Permalink to &quot;三、跌價損失風險與產業去庫存壓力&quot;">​</a></h3><ul><li><strong>核心重點</strong>：存貨天數13.2天遠低於一般製造業水準，備抵跌價損失3,647萬佔存貨淨額6.2%，2025年迴轉利益3,391萬，等於實際淨提列僅256萬。</li><li><strong>深度見解</strong>：封測產業特性為代工服務、原料隨領用消耗，存貨跌價風險本質低於品牌電子業。72%原料多為進口晶粒、導線架等標準化封裝材料，具市場流通性。製成品僅1,389萬（不足一個月營收的1/100），即使全部報廢對淨利影響微乎其微。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：存貨從2024Q4谷底大幅彈升41.7%，若2026年全球半導體景氣反轉下行，當前高水位存貨可能面臨去化壓力。2025年資本支出高達53.1億（PPE增加），若產能利用率下滑，折舊壓力將侵蝕毛利率。</li><li><strong>空頭風險二</strong>：長期借款從2024Q4的55.2億攀升至2025Q4的74.1億（+34.3%），雖利率環境尚稱寬鬆，但若央行持續升息，2025年利息費用已從2.42億增至2.19億（全年），未來再融資成本上升將壓縮獲利。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>：OK — 2024Q1至2025Q4共8季資產負債表、現金流量表、月營收數據完整取得。</li><li><strong>yfinance</strong>：未獨立驗證（FinMind數據已涵蓋所需項目）。</li><li><strong>年報/法說</strong>：OK — 2025_Q4_6257_合併.pdf 第35頁存貨組成明細、第26頁存貨會計政策、第12頁營業成本。</li><li><strong>關鍵核對碼</strong>：存貨淨額588,253仟元（FinMind）= 588,253仟元（年報第35頁），完全勾稽。</li></ul>',18)])])}const g=t(e,[["render",o]]);export{u as __pageData,g as default};
